 1	import { Badge, MenuToggle, MenuToggleElement, Select, SelectOption } from '@patternfly/react-core';
 2	import _ from 'lodash';
 3	import * as React from 'react';
 4	import { useTranslation } from 'react-i18next';
 5	import { doesIncludeFilter, Filter, findFromFilters, removeFromFilters } from '../../../model/filters';
 6	import { QuickFilter } from '../../../model/quick-filters';
 7	import { useOutsideClickEvent } from '../../../utils/outside-hook';
 8	import { QuickFiltersIcon } from '../../icons';
 9	
10	export interface QuickFiltersProps {
11	  quickFilters: QuickFilter[];
12	  activeFilters: Filter[];
13	  setFilters: (filters: Filter[]) => void;
14	}
15	
16	export const QuickFilters: React.FC<QuickFiltersProps> = ({ quickFilters, activeFilters, setFilters }) => {
17	  const { t } = useTranslation('plugin__netobserv-plugin');
18	  const ref = useOutsideClickEvent(() => setOpen(false));
19	  const [isOpen, setOpen] = React.useState(false);
20	  const [selectedList, setSelectedList] = React.useState([] as string[]);
21	
22	  React.useEffect(() => {
23	    // Init seletected filters: a quick filter is selected when every filter it contains is included in active filters
24	    const selected = quickFilters
25	      .filter(qf => {
26	        return qf.filters.every(qff => doesIncludeFilter(activeFilters, qff, qff.values));
27	      })
28	      .map(qf => qf.name);
29	    setSelectedList(selected);
30	  }, [quickFilters, activeFilters]);
31	
32	  const onSelect = (__: unknown, selectedName: string) => {
33	    const selected = quickFilters.find(qf => qf.name === selectedName);
34	    if (!selected) {
35	      return;
36	    }
37	    const isDelete = selectedList.includes(selectedName);
38	    let newFilters = _.cloneDeep(activeFilters);
39	    selected.filters.forEach(qf => {
40	      const found = findFromFilters(newFilters, qf);
41	      if (found) {
42	        if (isDelete) {
43	          // Remove all quick-filter values from the active filter values
44	          const qfValues = qf.values.map(v => v.v);
45	          found.values = found.values.filter(v => !qfValues.includes(v.v));
46	          if (found.values.length === 0) {
47	            newFilters = removeFromFilters(newFilters, qf);
48	          }
49	        } else {
50	          // Add all quick-filter values into the active filter if they're not already there
51	          qf.values.forEach(val => {
52	            if (!found.values.map(v => v.v).includes(val.v)) {
53	              found.values.push(val);
54	            }
55	          });
56	        }
57	      } else {
58	        newFilters.push(_.cloneDeep(qf));
59	      }
60	    });
61	    setFilters(newFilters);
62	  };
63	
64	  return (
65	    <div id="quick-filters-dropdown-container" data-test="quick-filters-dropdown-container" ref={ref}>
66	      <Select
67	        data-test="quick-filters-dropdown"
68	        id="quick-filters-dropdown"
69	        isOpen={isOpen}
70	        onSelect={onSelect}
71	        toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
72	          <MenuToggle ref={toggleRef} onClick={() => setOpen(!isOpen)} isExpanded={isOpen}>
73	            <>
74	              <QuickFiltersIcon /> {t('Quick filters')}
75	              {selectedList.length > 0 && <Badge isRead>{selectedList.length}</Badge>}
76	            </>
77	          </MenuToggle>
78	        )}
79	        selected={selectedList}
80	      >
81	        {quickFilters.map(qf => {
82	          return (
83	            <SelectOption
84	              hasCheckbox
85	              isSelected={selectedList.includes(qf.name)}
86	              id={`quick-filter-option-${qf.name}`}
87	              key={qf.name}
88	              value={qf.name}
89	            >
90	              {qf.name}
91	            </SelectOption>
92	          );
93	        })}
94	      </Select>
95	    </div>
96	  );
97	};

